---
import BaseLayout from "@/layouts/base.astro";
import ProjectCard from "@/components/project-card.astro";
import AwardRow from "@/components/award-row.astro";
import ServiceList from "@/components/service-list.astro";
import HighlightCard from "@/components/highlight-card.astro";
import BlogCard from "@/components/blog-card.astro";

const projectMetrics = [
  { value: "59%", label: "Conversion rate", trend: "up" as const },
  { value: "12%", label: "Avg. order", trend: "up" as const },
  { value: "34%", label: "Orders", trend: "up" as const },
];

const awards = [
  { award: "Red Dot", year: 2025, project: "mishmash" },
  { award: "Ecommerce Awards", year: 2025, project: "Hey Harper" },
  { award: "Awwwards SOTD", year: 2025, project: "mishmash" },
  { award: "European Design Awards", year: 2025, project: "mishmash" },
  { award: "IF Design Award", year: 2024, project: "mishmash" },
  { award: "German Design Award", year: 2024, project: "mishmash" },
  { award: "European Design Awards", year: 2024, project: "Passaporte Natura" },
  { award: "Awwwards SOTD", year: 2024, project: "Dia" },
  { award: "German Design Award", year: 2024, project: "Zoko" },
  { award: "Red Dot", year: 2024, project: "Zoko" },
];

const designServices = [
  { label: "User Experience Design" },
  { label: "Interface Design" },
  { label: "Interaction Design" },
  { label: "Icon Design" },
  { label: "Product Strategy" },
  { label: "Conversion Optimisation" },
  { label: "Prototyping & Testing" },
  { label: "Design Systems" },
  { label: "Branding" },
];

const devServices = [
  { label: "React & Next.js" },
  { label: "Swift/iOS" },
  { label: "Kotlin/Android" },
  { label: "Node.js & APIs" },
  { label: "Cloud & DevOps" },
  { label: "QA & Testing" },
  { label: "Analytics" },
];

const blogPosts = [
  {
    title: "How we built a design system in 3 weeks",
    author: "Ryan Ziegler",
    role: "CEO of Certainty Software",
    tags: ["Design", "Code"],
  },
  {
    title: "The future of e-commerce design",
    author: "Ryan Ziegler",
    role: "CEO of Certainty Software",
    tags: ["Design", "Code"],
  },
  { title: "Why we switched to Astro", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  {
    title: "Building accessible interfaces",
    author: "Ryan Ziegler",
    role: "CEO of Certainty Software",
    tags: ["Design", "Code"],
  },
];
---

<BaseLayout
  title="Significa — Design and Development Agency"
  description="We are a design and development agency building digital products that work beautifully. From strategy to code, we deliver user-centred platforms for ambitious businesses."
>
  <div class="page">
    <!-- 1. Hero -->
    <section class="hero">
      <div class="hero-top">
        <h1 class="hero-title">Significa®</h1>
        <p class="hero-subtitle">
          digital<br />something
        </p>
      </div>
      <div class="hero-labels">
        <div class="hero-label-row">
          Red Dot 2025 · mishmash &nbsp;·&nbsp; Ecommerce Awards 2025 · Hey Harper &nbsp;·&nbsp; Awwwards Site of the Day 2025 ·
          mishmash
        </div>
        <div class="hero-label-row">
          European Design Awards 2025 · mishmash &nbsp;·&nbsp; IF Design Award 2024 · mishmash &nbsp;·&nbsp; German Design Award
          2024 · mishmash
        </div>
        <div class="hero-label-row">
          European Design Awards 2024 · Passaporte Natura &nbsp;·&nbsp; Awwwards SOTD 2024 · Dia &nbsp;·&nbsp; German Design
          Award 2024 · Zoko
        </div>
        <div class="hero-label-row">
          Red Dot 2024 · Zoko &nbsp;·&nbsp; Red Dot 2025 · mishmash &nbsp;·&nbsp; Ecommerce Awards 2025 · Hey Harper
          &nbsp;·&nbsp; Awwwards SOTD 2025 · mishmash
        </div>
      </div>
    </section>

    <!-- 2. Showreel -->
    <section class="showreel"></section>

    <!-- 3. Intro -->
    <section class="intro">
      <div class="intro-inner">
        <h2 class="intro-title">From strategy to code, we deliver user-centred platforms for ambitious businesses.</h2>
        <p class="intro-body">
          Whether it's an e-commerce shop, a mobile app, a ticketing platform, or a design system, we'll build it with care and
          curiosity, backed by +10 years of expertise, recognised by +20 international awards.
        </p>
      </div>
    </section>

    <!-- 4. Prizes (2x2 grid) -->
    <section class="prizes">
      <div class="prizes-grid">
        <ProjectCard title="mishmash" metrics={projectMetrics} bg="var(--blue-50)" fg="var(--beige-950)" />
        <ProjectCard title="Hey Harper" metrics={projectMetrics} bg="var(--beige-50)" fg="var(--beige-950)" />
        <ProjectCard title="Dia" metrics={projectMetrics} bg="var(--beige-50)" fg="var(--beige-950)" />
        <div class="awards-card">
          <div class="awards-card-header">
            <h3 class="awards-card-title">International recognition.</h3>
            <p class="awards-card-subtitle">We've earned 20+ awards</p>
          </div>
          <div class="awards-card-list">
            {awards.map((a) => <AwardRow award={a.award} year={a.year} project={a.project} />)}
          </div>
        </div>
      </div>
    </section>

    <!-- 5. Services -->
    <section class="services">
      <ServiceList title="Transforming insights into effective experiences." items={designServices} />
      <ServiceList title="Building in-house with precision and care." items={devServices} />
    </section>

    <!-- 6. Highlights -->
    <section class="highlights">
      <div class="highlights-grid">
        <div class="highlights-large">
          <HighlightCard
            title="You'll enjoy our process as much as you enjoy your product. Free promise."
            size="large"
            bg="var(--beige-50)"
          />
        </div>
        <div class="highlights-small">
          <HighlightCard
            title="Bring your specs to Significa but give them the creative freedom to unleash the best possible design and solution for your needs."
            subtitle="84.7% Customer experience score"
            size="small"
            bg="var(--beige-100)"
          />
        </div>
      </div>
    </section>

    <!-- 7. Blog -->
    <section class="blog">
      <div class="blog-grid">
        {blogPosts.map((post) => <BlogCard title={post.title} author={post.author} role={post.role} tags={post.tags} />)}
      </div>
    </section>
  </div>
</BaseLayout>

<style>
  /* ============================================================
     Page container
     ============================================================ */
  .page {
    max-width: 1512px;
    margin: 0 auto;
    padding: 0 8px;
    display: flex;
    flex-direction: column;
    gap: 8px;
  }

  /* ============================================================
     1. Hero
     ============================================================ */
  .hero {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    min-height: 560px;
    background: var(--color-surface);
    border-radius: 8px;
    padding: 2rem;
  }

  .hero-top {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
  }

  .hero-title {
    font-family: var(--font-sans);
    font-size: var(--text-2xl);
    font-weight: var(--weight-medium);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0;
  }

  .hero-subtitle {
    font-family: var(--font-sans);
    font-size: var(--text-2xl);
    font-weight: var(--weight-normal);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0;
  }

  .hero-labels {
    display: flex;
    flex-direction: column;
    gap: 0;
  }

  .hero-label-row {
    height: 64px;
    display: flex;
    align-items: center;
    font-size: var(--text-sm);
    color: var(--color-text-muted);
    overflow: hidden;
    white-space: nowrap;
    text-overflow: ellipsis;
  }

  /* ============================================================
     2. Showreel
     ============================================================ */
  .showreel {
    min-height: 560px;
    background: var(--beige-100);
    border-radius: 8px;
  }

  /* ============================================================
     3. Intro
     ============================================================ */
  .intro {
    padding: 200px 0 100px;
  }

  .intro-inner {
    max-width: 500px;
    margin: 0 auto;
    text-align: center;
  }

  .intro-title {
    font-size: var(--text-2xl);
    font-weight: var(--weight-medium);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0 0 1.5rem;
  }

  .intro-body {
    font-size: var(--text-lg);
    font-weight: var(--weight-normal);
    line-height: var(--leading-normal);
    color: var(--color-text-muted);
    margin: 0;
  }

  /* ============================================================
     4. Prizes (2x2 grid)
     ============================================================ */
  .prizes-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
  }

  .awards-card {
    aspect-ratio: 1 / 1;
    border-radius: 8px;
    overflow: hidden;
    background: var(--beige-50);
    color: var(--beige-950);
    display: flex;
    flex-direction: column;
  }

  .awards-card-header {
    padding: 16px;
    flex-shrink: 0;
  }

  .awards-card-title {
    font-family: var(--font-display);
    font-size: var(--text-2xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    margin: 0 0 0.25rem;
  }

  .awards-card-subtitle {
    font-family: var(--font-display);
    font-size: var(--text-base);
    font-weight: var(--weight-normal);
    opacity: 0.7;
    margin: 0;
  }

  .awards-card-list {
    flex: 1;
    overflow-y: auto;
  }

  /* ============================================================
     5. Services
     ============================================================ */
  .services {
    display: flex;
    flex-direction: column;
    gap: 6rem;
    padding: 8rem 2rem;
    max-width: var(--max-width);
    margin: 0 auto;
    width: 100%;
    box-sizing: border-box;
  }

  /* ============================================================
     6. Highlights
     ============================================================ */
  .highlights-grid {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 8px;
  }

  .highlights-large,
  .highlights-small {
    min-height: 20rem;
  }

  /* ============================================================
     7. Blog
     ============================================================ */
  .blog-grid {
    display: grid;
    grid-template-columns: repeat(4, 1fr);
    gap: 8px;
  }

  /* ============================================================
     Responsive
     ============================================================ */
  @media (max-width: 1024px) {
    .prizes-grid {
      grid-template-columns: 1fr;
    }

    .highlights-grid {
      grid-template-columns: 1fr;
    }

    .blog-grid {
      grid-template-columns: repeat(2, 1fr);
    }

    .services {
      padding: 4rem 1.5rem;
      gap: 4rem;
    }
  }

  @media (max-width: 640px) {
    .blog-grid {
      grid-template-columns: 1fr;
    }

    .hero {
      min-height: 400px;
      padding: 1.5rem;
    }

    .intro {
      padding: 100px 1rem 60px;
    }

    .services {
      padding: 3rem 1rem;
      gap: 3rem;
    }
  }
</style>

import { defineCollection, reference, z } from "astro:content";
import { glob, type Loader } from "astro/loaders";

// ============================================================
// Shared schemas (reusable across collections)
// ============================================================

const seoSchema = z.object({
  metaTitle: z.string().optional(),
  metaDescription: z.string().optional(),
  ogImage: z.string().optional(),
});

/**
 * A single metric shown on project cards (e.g. "55%↑", "3.2x").
 * Used in project frontmatter and rendered on the homepage showcase.
 */
const metricSchema = z.object({
  value: z.string(),
  label: z.string(),
});

// ============================================================
// Loader
// ============================================================
const contentLoader = ({ base, extensions }: { extensions: string[]; base: string }): Loader => {
  // id generation: strip file extensions for clean URLs
  const stripExtension = ({ entry }: { entry: string }) => {
    return entry.replace(/\.(mdx?|yaml)$/, "");
  };

  // filter drafts only in production
  const draftFilter = import.meta.env.MODE === "development" ? "**" : "!(*.draft)";
  // filter extensions
  const extensionFilter = extensions.length > 1 ? `{${extensions.join(",")}}` : extensions[0];

  return glob({
    pattern: `**/${draftFilter}.${extensionFilter}`,
    base,
    generateId: stripExtension,
  });
};

// ============================================================
// Collections
// ============================================================

const projects = defineCollection({
  loader: contentLoader({
    base: "src/content/projects",
    extensions: ["mdx"],
  }),
  schema: z.object({
    title: z.string(),
    tagline: z.string().optional(),
    client: z.string().optional(),
    date: z.coerce.date(),
    thumbnail: z.string(),
    /** Large hero image for homepage showcase and project detail header */
    heroImage: z.string().optional(),
    tags: z.array(z.string()).default([]),
    /** Industry categories for filtering (e.g., "fintech", "e-commerce", "healthcare") */
    industry: z.array(z.string()).default([]),
    /** Deliverable types for filtering (e.g., "website", "mobile-app", "design-system") */
    deliverable: z.array(z.string()).default([]),
    /** Key metrics shown on project cards (e.g. conversion uplift, NPS) */
    metrics: z.array(metricSchema).default([]),
    seo: seoSchema.optional(),
    relatedProjects: z.array(reference("projects")).default([]),
  }),
});

const blog = defineCollection({
  loader: contentLoader({
    extensions: ["md", "mdx"],
    base: "src/content/blog",
  }),
  schema: z.object({
    title: z.string(),
    description: z.string().optional(),
    date: z.coerce.date(),
    author: z.string().optional(),
    thumbnail: z.string().optional(),
    tags: z.array(z.string()).default([]),
    seo: seoSchema.optional(),
    relatedProjects: z.array(reference("projects")).default([]),
  }),
});

const playground = defineCollection({
  loader: contentLoader({
    extensions: ["md", "mdx"],
    base: "src/content/playground",
  }),
  schema: z.object({
    title: z.string(),
    description: z.string(),
    date: z.coerce.date(),
    repoUrl: z.string().url().optional(),
    thumbnail: z.string().optional(),
    tags: z.array(z.string()).default([]),
    seo: seoSchema.optional(),
  }),
});

const pages = defineCollection({
  loader: contentLoader({
    extensions: ["mdx"],
    base: "src/content/pages",
  }),
  schema: z.object({
    title: z.string(),
    seo: seoSchema.optional(),
  }),
});

// ============================================================
// Homepage highlights
// ============================================================
// Each entry references an item in another collection.
// Astro validates every slug at build time: typos break the build, not prod.

const highlights = defineCollection({
  loader: contentLoader({
    extensions: ["yaml"],
    base: "src/content/highlights",
  }),
  schema: z.object({
    label: z.string().optional(),
    source: z.discriminatedUnion("collection", [
      z.object({
        collection: z.literal("projects"),
        entry: reference("projects"),
      }),
      z.object({
        collection: z.literal("blog"),
        entry: reference("blog"),
      }),
      z.object({
        collection: z.literal("playground"),
        entry: reference("playground"),
      }),
    ]),
    order: z.number(),
  }),
});

// ============================================================
// Clients — logo strip, references across the site
// ============================================================
// YAML entries for each client. Used by the homepage logo strip,
// project pages, and anywhere we need to show who we work with.

const clients = defineCollection({
  loader: contentLoader({
    extensions: ["yaml"],
    base: "src/content/clients",
  }),
  schema: z.object({
    name: z.string(),
    /** Path to SVG logo in public/ (e.g. "/logos/boeing.svg") */
    logo: z.string(),
    url: z.string().url().optional(),
    order: z.number().default(0),
  }),
});

// ============================================================
// Testimonials — customer quotes
// ============================================================
// YAML entries for client testimonials. Used on the homepage,
// and potentially on project pages or a dedicated social proof section.

const testimonials = defineCollection({
  loader: contentLoader({
    extensions: ["yaml"],
    base: "src/content/testimonials",
  }),
  schema: z.object({
    quote: z.string(),
    author: z.string(),
    role: z.string(),
    company: z.string(),
    /** CDN path to author avatar (optional) */
    avatar: z.string().optional(),
    order: z.number().default(0),
  }),
});

// ============================================================
// Awards — recognition and validation
// ============================================================
// YAML entries for awards and recognitions. Shown on the homepage
// in a scrollable list. Each award references the project it was for.

const awards = defineCollection({
  loader: contentLoader({
    extensions: ["yaml"],
    base: "src/content/awards",
  }),
  schema: z.object({
    /** Award name (e.g. "Red Dot", "Awwwards Site of the Day") */
    award: z.string(),
    year: z.number(),
    /** Project that won the award — validated at build time */
    project: reference("projects"),
    /** External link to the award page (optional) */
    url: z.string().url().optional(),
    order: z.number().default(0),
  }),
});

// ============================================================
// Handbook groups — visual categories on the handbook index
// ============================================================
// Each group has a title and an order. Handbook pages reference
// a group by its filename slug (e.g. "engineering", "design").

const handbookGroups = defineCollection({
  loader: contentLoader({
    extensions: ["yaml"],
    base: "src/content/handbook-groups",
  }),
  schema: z.object({
    title: z.string(),
    order: z.number(),
  }),
});

// ============================================================
// Handbook — internal company documentation
// ============================================================
// MDX files in src/content/handbook/, organized in directories
// for parent-child nesting. File path determines URL:
//   culture.mdx                      → /handbook/culture
//   how-we-build-software.mdx        → /handbook/how-we-build-software
//   how-we-build-software/front-end.mdx → /handbook/how-we-build-software/front-end
//
// `group` references a handbook-groups entry (validated at build time).
// `order` controls sort position within a group on the index page.
// Parent pages (those with children) are identified at query time
// by checking if any other entry's id starts with their id + "/".

const handbook = defineCollection({
  loader: contentLoader({
    extensions: ["mdx"],
    base: "src/content/handbook",
  }),
  schema: z.object({
    title: z.string(),
    description: z.string().optional(),
    /** Last updated date */
    date: z.coerce.date(),
    /** Cover image displayed at the top of the page (CDN path) */
    coverImage: z.string().optional(),
    /** Reference to a handbook-groups entry */
    group: reference("handbook-groups"),
    /** Sort order within the group on the index page */
    order: z.number().default(0),
    seo: seoSchema.optional(),
  }),
});

export const collections = {
  projects,
  blog,
  playground,
  pages,
  highlights,
  clients,
  testimonials,
  awards,
  "handbook-groups": handbookGroups,
  handbook,
};

