---
import { ClientRouter } from "astro:transitions";
import SEO from "@/components/seo.astro";
import Header from "@/components/header.astro";
import Footer from "@/components/footer.astro";
import { organizationJsonLd } from "@/lib/seo";
import "@/styles/global.css";

interface Props {
  title: string;
  description: string;
  ogImage?: string;
  type?: "website" | "article";
  publishedAt?: Date;
}

const { title, description, ogImage, type, publishedAt } = Astro.props;
---

<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <link rel="icon" type="image/svg+xml" href="/favicon.svg" />
    <link rel="preconnect" href="https://fonts.googleapis.com" />
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin />
    <link href="https://fonts.googleapis.com/css2?family=Google+Sans+Flex:wght@100..900&display=swap" rel="stylesheet" />
    <SEO title={title} description={description} ogImage={ogImage} type={type} publishedAt={publishedAt} />
    <ClientRouter />
    <script is:inline type="application/ld+json" set:html={JSON.stringify(organizationJsonLd())} />
  </head>
  <body>
    <a href="#main-content" class="skip-link">Skip to content</a>
    <Header />
    <main id="main-content">
      <slot />
    </main>
    <Footer />
  </body>
</html>

