---
import BaseLayout from "@/layouts/base.astro";
import ProjectCard from "@/components/project-card.astro";
import AwardRow from "@/components/award-row.astro";
import ServiceList from "@/components/service-list.astro";
import HighlightCard from "@/components/highlight-card.astro";
import BlogCard from "@/components/blog-card.astro";
import { getResolvedHighlights } from "@/lib/collections";

const projectMetrics = [
  { value: "59%", label: "Conversion rate", trend: "up" as const },
  { value: "12%", label: "Avg. order", trend: "up" as const },
  { value: "34%", label: "Orders", trend: "up" as const },
];

const awards = [
  { award: "Red Dot", year: 2025, project: "mishmash" },
  { award: "Ecommerce Awards", year: 2025, project: "Hey Harper" },
  { award: "Awwwards SOTD", year: 2025, project: "mishmash" },
  { award: "European Design Awards", year: 2025, project: "mishmash" },
  { award: "IF Design Award", year: 2024, project: "mishmash" },
  { award: "German Design Award", year: 2024, project: "mishmash" },
  { award: "European Design Awards", year: 2024, project: "Passaporte Natura" },
  { award: "Awwwards SOTD", year: 2024, project: "Dia" },
  { award: "German Design Award", year: 2024, project: "Zoko" },
  { award: "Red Dot", year: 2024, project: "Zoko" },
];

const designServices = [
  { label: "User Experience Design" },
  { label: "Interface Design" },
  { label: "Interaction Design" },
  { label: "Icon Design" },
  { label: "Product Strategy" },
  { label: "Conversion Optimisation" },
  { label: "Prototyping & Testing" },
  { label: "Design Systems" },
  { label: "Branding" },
];

const devServices = [
  { label: "React & Next.js" },
  { label: "Swift/iOS" },
  { label: "Kotlin/Android" },
  { label: "Node.js & APIs" },
  { label: "Cloud & DevOps" },
  { label: "QA & Testing" },
  { label: "Analytics" },
];

const blogPosts = [
  {
    title: "How we built a design system in 3 weeks",
    author: "Ryan Ziegler",
    role: "CEO of Certainty Software",
    tags: ["Design", "Code"],
  },
  {
    title: "The future of e-commerce design",
    author: "Ryan Ziegler",
    role: "CEO of Certainty Software",
    tags: ["Design", "Code"],
  },
  { title: "Why we switched to Astro", author: "Ryan Ziegler", role: "CEO of Certainty Software", tags: ["Design", "Code"] },
  {
    title: "Building accessible interfaces",
    author: "Ryan Ziegler",
    role: "CEO of Certainty Software",
    tags: ["Design", "Code"],
  },
];

/* ── Hero highlights ── */
const highlights = await getResolvedHighlights();

const collectionPathMap: Record<string, string> = {
  blog: "/blog",
  projects: "/projects",
  playground: "/labs",
};

function estimateReadingTime(body: string | undefined): number | null {
  if (!body) return null;
  const words = body.trim().split(/\s+/).filter(Boolean).length;
  return Math.max(1, Math.ceil(words / 200));
}

const heroHighlights = highlights.map((h) => ({
  title: h.entry?.data.title ?? "Untitled",
  href: `${collectionPathMap[h.collection] ?? ""}/${h.entry?.id}`,
  label: h.label,
  readingTime: estimateReadingTime((h.entry as { body?: string })?.body),
}));
---

<BaseLayout
  title="Significa — Design and Development Agency"
  description="We are a design and development agency building digital products that work beautifully. From strategy to code, we deliver user-centred platforms for ambitious businesses."
>
  <div class="page">
    <!-- 1. Hero -->
    <section class="hero">
      <div class="hero-heading">
        <h1 class="hero-title">Significa®</h1>
        <p class="hero-subtitle">Mean something.</p>
      </div>

      <nav class="hero-highlights" aria-label="Featured articles">
        {heroHighlights.map((item) => (
          <a class="highlight-row" href={item.href}>
            {item.label && <span class="highlight-icon" aria-hidden="true" />}
            <span class="highlight-title">{item.title}</span>
            <span class="highlight-meta">
              {item.readingTime && (
                <span class="highlight-time">{item.readingTime} min</span>
              )}
              <svg class="highlight-arrow" width="14" height="14" viewBox="0 0 14 14" fill="none" aria-hidden="true">
                <path d="M3 11L11 3M11 3H5M11 3V9" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"/>
              </svg>
            </span>
          </a>
        ))}
      </nav>
    </section>

    <!-- 2. Showreel -->
    <section class="showreel"></section>

    <!-- 3. Intro -->
    <section class="intro">
      <div class="intro-inner">
        <h2 class="intro-title">From strategy to code, we deliver user-centred platforms for ambitious businesses.</h2>
        <p class="intro-body">
          Whether it's an e-commerce shop, a mobile app, a ticketing platform, or a design system, we'll build it with care and
          curiosity, backed by +10 years of expertise, recognised by +20 international awards.
        </p>
      </div>
    </section>

    <!-- 4. Prizes (2x2 grid) -->
    <section class="prizes">
      <div class="prizes-grid">
        <ProjectCard title="mishmash" metrics={projectMetrics} bg="var(--blue-50)" fg="var(--beige-950)" />
        <ProjectCard title="Hey Harper" metrics={projectMetrics} bg="var(--beige-50)" fg="var(--beige-950)" />
        <ProjectCard title="Dia" metrics={projectMetrics} bg="var(--beige-50)" fg="var(--beige-950)" />
        <div class="awards-card">
          <div class="awards-card-header">
            <h3 class="awards-card-title">International recognition.</h3>
            <p class="awards-card-subtitle">We've earned 20+ awards</p>
          </div>
          <div class="awards-card-list">
            {awards.map((a) => <AwardRow award={a.award} year={a.year} project={a.project} />)}
          </div>
        </div>
      </div>
    </section>

    <!-- 5. Services -->
    <section class="services">
      <ServiceList title="Transforming insights into effective experiences." items={designServices} />
      <ServiceList title="Building in-house with precision and care." items={devServices} />
    </section>

    <!-- 6. Highlights -->
    <section class="highlights">
      <div class="highlights-grid">
        <div class="highlights-large">
          <HighlightCard
            title="You'll enjoy our process as much as you enjoy your product. Free promise."
            size="large"
            bg="var(--beige-50)"
          />
        </div>
        <div class="highlights-small">
          <HighlightCard
            title="Bring your specs to Significa but give them the creative freedom to unleash the best possible design and solution for your needs."
            subtitle="84.7% Customer experience score"
            size="small"
            bg="var(--beige-100)"
          />
        </div>
      </div>
    </section>

    <!-- 7. Blog -->
    <section class="blog">
      <div class="blog-grid">
        {blogPosts.map((post) => <BlogCard title={post.title} author={post.author} role={post.role} tags={post.tags} />)}
      </div>
    </section>
  </div>
</BaseLayout>

<style>
  /* ============================================================
     Page container
     ============================================================ */
  .page {
    max-width: 1512px;
    margin: 0 auto;
    padding: 0.5rem 0.5rem 0;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
  }

  /* ============================================================
     1. Hero
     ============================================================ */
  .hero {
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    min-height: calc(100svh - 7.5rem);
    background: var(--color-surface);
    border-radius: 0.75rem;
    border: 0.5px solid var(--color-border-subtle);
    overflow: hidden;
  }

  .hero-heading {
    padding: 1rem;
  }

  .hero-title {
    font-family: var(--font-sans);
    font-size: 1.75rem;
    font-weight: var(--weight-medium);
    line-height: 1.15;
    letter-spacing: -0.0175rem;
    color: var(--color-text);
    margin: 0;
  }

  .hero-subtitle {
    font-family: var(--font-sans);
    font-size: 1.75rem;
    font-weight: var(--weight-normal);
    line-height: 1.15;
    letter-spacing: -0.0175rem;
    color: var(--color-text-muted);
    margin: 0;
  }

  /* ── Hero highlight rows ── */
  .hero-highlights {
    display: flex;
    flex-direction: column;
  }

  .highlight-row {
    display: flex;
    align-items: center;
    gap: 1rem;
    padding: 22px 1rem;
    border-top: 0.5px solid var(--color-border-subtle);
    text-decoration: none;
    color: inherit;
    transition: background var(--duration-fast) var(--ease-out);
  }

  .highlight-row:hover {
    background: var(--color-surface-alt);
  }

  .highlight-icon {
    width: 20px;
    height: 20px;
    border-radius: 4px;
    background: var(--gray-300);
    flex-shrink: 0;
    transition: background var(--duration-fast) var(--ease-out);
  }

  .highlight-row:hover .highlight-icon {
    background: var(--color-text);
  }

  .highlight-title {
    flex: 1;
    font-family: var(--font-display);
    font-size: 0.875rem;
    font-weight: var(--weight-medium);
    line-height: 1.3;
    letter-spacing: 0.035rem;
    text-transform: uppercase;
    color: var(--color-text-muted);
    min-width: 0;
    transition: color var(--duration-fast) var(--ease-out);
  }

  .highlight-row:hover .highlight-title {
    color: var(--color-text);
  }

  .highlight-meta {
    display: flex;
    align-items: center;
    gap: 1rem;
    flex-shrink: 0;
  }

  .highlight-time {
    font-family: var(--font-display);
    font-size: 0.6875rem;
    font-weight: var(--weight-medium);
    line-height: 1.24;
    letter-spacing: 0.03438rem;
    text-transform: uppercase;
    color: var(--color-text-muted);
    white-space: nowrap;
    transition: color var(--duration-fast) var(--ease-out);
  }

  .highlight-row:hover .highlight-time {
    color: var(--color-text);
  }

  .highlight-arrow {
    width: 14px;
    height: 14px;
    color: var(--color-text-muted);
    flex-shrink: 0;
    transition: color var(--duration-fast) var(--ease-out);
  }

  .highlight-row:hover .highlight-arrow {
    color: var(--orange-500);
  }

  /* ============================================================
     2. Showreel
     ============================================================ */
  .showreel {
    min-height: 560px;
    background: var(--beige-100);
    border-radius: 8px;
  }

  /* ============================================================
     3. Intro
     ============================================================ */
  .intro {
    padding: 200px 0 100px;
  }

  .intro-inner {
    max-width: 500px;
    margin: 0 auto;
    text-align: center;
  }

  .intro-title {
    font-size: var(--text-2xl);
    font-weight: var(--weight-medium);
    line-height: var(--leading-tight);
    color: var(--color-text);
    margin: 0 0 1.5rem;
  }

  .intro-body {
    font-size: var(--text-lg);
    font-weight: var(--weight-normal);
    line-height: var(--leading-normal);
    color: var(--color-text-muted);
    margin: 0;
  }

  /* ============================================================
     4. Prizes (2x2 grid)
     ============================================================ */
  .prizes-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
  }

  .awards-card {
    aspect-ratio: 1 / 1;
    border-radius: 8px;
    overflow: hidden;
    background: var(--beige-50);
    color: var(--beige-950);
    display: flex;
    flex-direction: column;
  }

  .awards-card-header {
    padding: 16px;
    flex-shrink: 0;
  }

  .awards-card-title {
    font-family: var(--font-display);
    font-size: var(--text-2xl);
    font-weight: var(--weight-bold);
    line-height: var(--leading-tight);
    margin: 0 0 0.25rem;
  }

  .awards-card-subtitle {
    font-family: var(--font-display);
    font-size: var(--text-base);
    font-weight: var(--weight-normal);
    opacity: 0.7;
    margin: 0;
  }

  .awards-card-list {
    flex: 1;
    overflow-y: auto;
  }

  /* ============================================================
     5. Services
     ============================================================ */
  .services {
    display: flex;
    flex-direction: column;
    gap: 6rem;
    padding: 8rem 2rem;
    max-width: var(--max-width);
    margin: 0 auto;
    width: 100%;
    box-sizing: border-box;
  }

  /* ============================================================
     6. Highlights
     ============================================================ */
  .highlights-grid {
    display: grid;
    grid-template-columns: 2fr 1fr;
    gap: 8px;
  }

  .highlights-large,
  .highlights-small {
    min-height: 20rem;
  }

