  1→import { getCollection, getEntry } from "astro:content";
  2→import type { CollectionEntry } from "astro:content";
  3→
  4→/**
  5→ * Get all projects, sorted by date descending.
  6→ */
  7→export async function getProjects() {
  8→  const projects = await getCollection("projects");
  9→  return projects.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
 10→}
 11→
 12→/**
 13→ * Get all blog posts, sorted by date descending.
 14→ */
 15→export async function getPosts() {
 16→  const posts = await getCollection("blog");
 17→  return posts.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
 18→}
 19→
 20→/**
 21→ * Get all playground entries, sorted by date descending.
 22→ */
 23→export async function getPlayground() {
 24→  const playground = await getCollection("playground");
 25→  return playground.sort((a, b) => b.data.date.getTime() - a.data.date.getTime());
 26→}
 27→
 28→/**
 29→ * Get all clients, sorted by order ascending.
 30→ */
 31→export async function getClients() {
 32→  const clients = await getCollection("clients");
 33→  return clients.sort((a, b) => a.data.order - b.data.order);
 34→}
 35→
 36→/**
 37→ * Get all testimonials, sorted by order ascending.
 38→ */
 39→export async function getTestimonials() {
 40→  const testimonials = await getCollection("testimonials");
 41→  return testimonials.sort((a, b) => a.data.order - b.data.order);
 42→}
 43→
 44→/**
 45→ * Get homepage highlights with their referenced entries resolved.
 46→ * Returns entries sorted by order, with the full referenced content entry attached.
 47→ */
 48→export async function getResolvedHighlights() {
 49→  const allHighlights = await getCollection("highlights");
 50→  const sorted = allHighlights.sort((a, b) => a.data.order - b.data.order);
 51→
 52→  const resolved = await Promise.all(
 53→    sorted.map(async (h) => {
 54→      const entry = await getEntry(h.data.source.collection, h.data.source.entry.id);
 55→      return {
 56→        label: h.data.label,
 57→        collection: h.data.source.collection,
 58→        entry,
 59→      };
 60→    })
 61→  );
 62→
 63→  return resolved;
 64→}
 65→
 66→/**
 67→ * Get all awards with their referenced projects resolved.
 68→ * Returns awards sorted by order, with the full project entry attached.
 69→ */
 70→export async function getAwards() {
 71→  const allAwards = await getCollection("awards");
 72→  const sorted = allAwards.sort((a, b) => a.data.order - b.data.order);
 73→
 74→  const resolved = await Promise.all(
 75→    sorted.map(async (a) => {
 76→      const project = await getEntry("projects", a.data.project.id);
 77→      return {
 78→        award: a.data.award,
 79→        year: a.data.year,
 80→        url: a.data.url,
 81→        project,
 82→      };
 83→    })
 84→  );
 85→
 86→  return resolved;
 87→}
 88→
 89→// ============================================================
 90→// Handbook helpers
 91→// ============================================================
 92→
 93→export type HandbookEntry = CollectionEntry<"handbook">;
 94→export type HandbookGroupEntry = CollectionEntry<"handbook-groups">;
 95→
 96→/**
 97→ * Get all handbook groups, sorted by order ascending.
 98→ */
 99→export async function getHandbookGroups() {
100→  const groups = await getCollection("handbook-groups");
101→  return groups.sort((a, b) => a.data.order - b.data.order);
102→}
103→
104→/**
105→ * Get all handbook pages, sorted by order ascending within each group.
106→ */
107→export async function getHandbookPages() {
108→  const pages = await getCollection("handbook");
109→  return pages.sort((a, b) => a.data.order - b.data.order);
110→}
111→
112→/**
113→ * Get only top-level handbook pages (no "/" in their id).
114→ * These are the pages shown directly under groups on the index.
115→ */
116→export async function getTopLevelHandbookPages() {
117→  const pages = await getHandbookPages();
118→  return pages.filter((p) => !p.id.includes("/"));
119→}
120→
121→/**
122→ * Get child pages of a given parent handbook page.
123→ * Children are pages whose id starts with `parentId + "/"`.
124→ */
125→export async function getHandbookChildren(parentId: string) {
126→  const pages = await getHandbookPages();
127→  const prefix = parentId + "/";
128→  // Only direct children — one level deep (no nested slashes after the prefix)
129→  return pages.filter((p) => {
130→    if (!p.id.startsWith(prefix)) return false;
131→    const remainder = p.id.slice(prefix.length);
132→    return !remainder.includes("/");
133→  });
134→}
135→
136→/**
137→ * Get the parent page of a handbook entry, if it has one.
138→ * Returns null for top-level pages.
139→ */
140→export async function getHandbookParent(entry: HandbookEntry) {
141→  const parts = entry.id.split("/");
142→  if (parts.length < 2) return null;
143→  const parentId = parts.slice(0, -1).join("/");
144→  const pages = await getHandbookPages();
145→  return pages.find((p) => p.id === parentId) ?? null;
146→}
147→
148→/**
149→ * Build the breadcrumb trail for a handbook page.
150→ * Returns entries from root to the current page (exclusive).
151→ */
152→export async function getHandbookBreadcrumbs(entry: HandbookEntry) {
153→  const parts = entry.id.split("/");
154→  if (parts.length < 2) return [];
155→
156→  const pages = await getHandbookPages();
157→  const breadcrumbs: HandbookEntry[] = [];
158→
159→  for (let i = 1; i < parts.length; i++) {
160→    const ancestorId = parts.slice(0, i).join("/");
161→    const ancestor = pages.find((p) => p.id === ancestorId);
162→    if (ancestor) breadcrumbs.push(ancestor);
163→  }
164→
165→  return breadcrumbs;
166→}
167→
168→/**
169→ * Get the full grouped handbook structure for the index page.
170→ * Returns groups in order, each with their top-level pages.
171→ * Pages with children have a `children` array attached.
172→ */
173→export async function getHandbookIndex() {
174→  const [groups, allPages] = await Promise.all([getHandbookGroups(), getHandbookPages()]);
175→
176→  const topLevel = allPages.filter((p) => !p.id.includes("/"));
177→
178→  return groups.map((group) => {
179→    const pages = topLevel
180→      .filter((p) => p.data.group.id === group.id)
181→      .map((page) => {
182→        const prefix = page.id + "/";
183→        const children = allPages.filter((p) => {
184→          if (!p.id.startsWith(prefix)) return false;
185→          return !p.id.slice(prefix.length).includes("/");
186→        });
187→        return { page, children };
188→      });
189→
190→    return { group, pages };
191→  });
192→}
